import React from 'react'
import { LoginBackGround } from '../assets/img';
import {motion} from 'framer-motion'

export const Login = () => {
  return (
    // <motion.img src={LoginBackGround} className='w-screen h-aotu'
    // // className="absolute w-[200%] h-full bg-[url('/your-image.jpg')] bg-cover bg-center"
    // animate={{ x: ["0%", "-50%", "0%"] }}
    // transition={{ repeat: Infinity, duration: 10, ease: "linear" }}/>
    // <div>Login</div>
    <div className="relative w-screen h-screen overflow-hidden flex justify-center items-center bg-black">
    {/* 运动的图片 */}
    <motion.img
      src={LoginBackGround}
      alt="Moving Background"
      className="absolute h-full w-auto min-w-[150%]" // 确保图片比屏幕宽
      animate={{ x: ["0%", "-50%", "0%"] }} // 左右循环
      transition={{ repeat: Infinity, duration: 10, ease: "linear" }}
    />

    {/* 前景内容 */}
    <div className="relative z-10 text-white text-4xl">
      前景内容
    </div>
  </div>
  )

}

export default Login;
